#include "controller.h"

#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static bool controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    bool turbidity_stale = false;
    bool level_stale = false;

    if (controller->has_valid_turbidity && (now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        turbidity_stale = true;
    }

    if (controller->has_valid_level && (now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        level_stale = true;
    }

    return turbidity_stale || level_stale;
}

static void controller_handle_turbidity_input(controller_t *controller, int turbidity_ntu, uint32_t now_ms)
{
    /* Update turbidity freshness and value */
    controller->has_valid_turbidity = true;
    controller->last_turbidity_ntu = turbidity_ntu;
    controller->last_turbidity_ms = now_ms;

    /* Handle malformed input (non-integer values are already filtered by protocol) */
    /* Negative or out-of-range values would be caught by protocol_parse_line */
}

static void controller_handle_level_input(controller_t *controller, int level, uint32_t now_ms)
{
    /* Update level freshness and value */
    controller->has_valid_level = true;
    controller->last_level = level;
    controller->last_level_ms = now_ms;
}

static void controller_handle_sensor_timeout(controller_t *controller)
{
    controller->has_valid_turbidity = false;
    controller->has_valid_level = false;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
    controller_set_safe_idle(controller);
}

static void controller_handle_invalid_input(controller_t *controller)
{
    controller->has_valid_turbidity = false;
    controller->has_valid_level = false;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
    controller_set_safe_idle(controller);
}

static void controller_handle_no_input(controller_t *controller)
{
    /* Do nothing - no state change */
}

static bool controller_should_enter_filtering(controller_t *controller)
{
    /* TURB > 35 AND LEVEL >= 40 */
    return (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) &&
           (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL);
}

static void controller_enter_filtering(controller_t *controller, uint32_t now_ms)
{
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->filter_on = true;
    controller->drain_open = false;
    /* Reset clear streak when entering filtering */
    controller->clear_streak_count = 0;
}

static bool controller_should_enter_settling(controller_t *controller)
{
    /* Clear streak reaches 3 while LEVEL >= 40 */
    return (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) &&
           (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL);
}

static void controller_enter_settling(controller_t *controller, uint32_t now_ms)
{
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->filter_on = false;
    controller->drain_open = false;
    controller->settling_started_ms = now_ms;
}

static bool controller_should_enter_draining(controller_t *controller, uint32_t now_ms)
{
    /* SETTLING has lasted at least 400ms, latest TURB <= 35, LEVEL >= 40 */
    bool settling_elapsed_enough = false;
    if (controller->state == CONTROLLER_STATE_SETTLING) {
        uint32_t settle_duration_ms = now_ms - controller->settling_started_ms;
        settling_elapsed_enough = (settle_duration_ms >= CONTROLLER_SETTLING_MS);
    }

    return settling_elapsed_enough &&
           (controller->clear_streak_count > 0) &&
           (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) &&
           (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL);
}

static void controller_enter_draining(controller_t *controller, uint32_t now_ms)
{
    controller->state = CONTROLLER_STATE_DRAINING;
    controller->filter_on = false;
    controller->drain_open = true;
}

static bool controller_should_return_to_filtering_from_settling(controller_t *controller)
{
    /* Valid TURB > 40 during SETTLING */
    return (controller->state == CONTROLLER_STATE_SETTLING) &&
           (controller->has_valid_turbidity) &&
           (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU);
}

static void controller_reset_to_filtering(controller_t *controller, uint32_t now_ms)
{
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->filter_on = true;
    controller->drain_open = false;
    /* Reset clear streak when returning to filtering */
    controller->clear_streak_count = 0;
}

static bool controller_should_return_to_filtering_from_draining(controller_t *controller)
{
    /* Valid TURB > 50 AND LEVEL >= 40 during DRAINING */
    return (controller->state == CONTROLLER_STATE_DRAINING) &&
           (controller->has_valid_turbidity) &&
           (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) &&
           (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL);
}

static void controller_handle_disturbance_during_draining(controller_t *controller, uint32_t now_ms)
{
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->filter_on = true;
    controller->drain_open = false;
    /* Reset clear streak */
    controller->clear_streak_count = 0;
}

static void controller_enter_complete(controller_t *controller)
{
    controller->state = CONTROLLER_STATE_COMPLETE;
    controller->filter_on = false;
    controller->drain_open = false;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Handle sensor timeout first - this forces safe idle */
    bool sensor_timeout_occurred = false;
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        sensor_timeout_occurred = true;
    } else if ((controller->has_valid_turbidity && input.kind == CONTROLLER_INPUT_NONE) ||
               (controller->has_valid_level && input.kind == CONTROLLER_INPUT_NONE)) {
        /* Timeout check: either sensor became stale */
        sensor_timeout_occurred = controller_check_sensor_timeout(controller, input.now_ms);
    }

    if (sensor_timeout_occurred) {
        controller_handle_sensor_timeout(controller);
        output.timed_out = true;
    } else if (input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY || input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        /* Malformed input - go to safe idle */
        controller_handle_invalid_input(controller);
        output.timed_out = true;
    } else if (input.kind == CONTROLLER_INPUT_NONE) {
        /* No new input - check for timeout condition */
        bool needs_reset = false;

        /* Check turbidity timeout */
        if (controller->has_valid_turbidity && (input.now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            needs_reset = true;
        }

        /* Check level timeout */
        if (controller->has_valid_level && (input.now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            needs_reset = true;
        }

        if (needs_reset) {
            controller_handle_sensor_timeout(controller);
            output.timed_out = true;
        }
    }

    /* Process valid sensor inputs */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller_handle_turbidity_input(controller, input.turbidity_ntu, input.now_ms);
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller_handle_level_input(controller, input.level, input.now_ms);
        break;
    default:
        /* No valid input */
        break;
    }

    /* Now apply control logic based on state and inputs */

    /* Check if we should enter COMPLETE (LEVEL < 15) */
    bool level_too_low = (controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL);

    /* SAFE_IDLE: stay here until both sensors valid, or LEVEL < 15 triggers COMPLETE */
    if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
        if (level_too_low) {
            controller_enter_complete(controller);
        } else if (controller->has_valid_turbidity && controller->has_valid_level) {
            /* Both sensors valid - check if we should start filtering */
            if (controller_should_enter_filtering(controller)) {
                controller_enter_filtering(controller, input.now_ms);
            }
        }
    }
    else if (controller->state == CONTROLLER_STATE_FILTERING) {
        /* Check for complete condition */
        if (level_too_low) {
            controller_enter_complete(controller);
        } else {
            /* Clear streak logic - only count valid TURB inputs while filtering */
            if (controller->has_valid_turbidity) {
                if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    /* Clear sample - increment streak */
                    controller->clear_streak_count++;
                } else {
                    /* Cloudy sample - reset streak */
                    controller->clear_streak_count = 0;
                }

                /* Check if we should enter settling */
                if (controller_should_enter_settling(controller)) {
                    controller_enter_settling(controller, input.now_ms);
                }
            }
        }
    }
    else if (controller->state == CONTROLLER_STATE_SETTLING) {
        /* Check for complete condition */
        if (level_too_low) {
            controller_enter_complete(controller);
        } else {
            /* Check for disturbance during settling (TURB > 40) */
            if (controller_should_return_to_filtering_from_settling(controller)) {
                controller_reset_to_filtering(controller, input.now_ms);
            } else {
                /* Check if we should enter draining */
                if (controller_should_enter_draining(controller, input.now_ms)) {
                    controller_enter_draining(controller, input.now_ms);
                }
            }
        }
    }
    else if (controller->state == CONTROLLER_STATE_DRAINING) {
        /* Check for complete condition */
        if (level_too_low) {
            controller_enter_complete(controller);
        } else {
            /* Check for disturbance during draining (TURB > 50 AND LEVEL >= 40) */
            if (controller_should_return_to_filtering_from_draining(controller)) {
                controller_handle_disturbance_during_draining(controller, input.now_ms);
            }
        }
    }
    else if (controller->state == CONTROLLER_STATE_COMPLETE) {
        /* Stay in COMPLETE until LEVEL >= 15 and both sensors valid */
        if (!level_too_low && controller->has_valid_turbidity && controller->has_valid_level) {
            /* Check if we should restart filtering */
            if (controller_should_enter_filtering(controller)) {
                controller_enter_filtering(controller, input.now_ms);
            }
        }
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

